<?php declare(strict_types=1); namespace Tests\Feature\FarmDirect; use App\Domains\FarmDirect\Models\FarmDirect; use Database\Factories\FarmDirect\FarmDirectFactory; use Tests\TestCase; final class FarmDirectTest extends TestCase { use \Illuminate\Foundation\Testing\DatabaseTransactions; public function test_can_create_product(): void { $item = FarmDirectFactory::new()->create(['tenant_id' => 1]); $this->assertDatabaseHas('farm_directs', ['id' => $item->id]); } public function test_organic_product(): void { $item = FarmDirectFactory::new()->organic()->create(['tenant_id' => 1]); $this->assertTrue($item->is_organic); } public function test_conventional_product(): void { $item = FarmDirectFactory::new()->conventional()->create(['tenant_id' => 1]); $this->assertFalse($item->is_organic); } public function test_product_type(): void { $item = FarmDirectFactory::new()->create(['tenant_id' => 1, 'product_type' => 'vegetables']); $this->assertEquals('vegetables', $item->product_type); } public function test_is_local(): void { $item = FarmDirectFactory::new()->create(['tenant_id' => 1]); $this->assertTrue($item->is_local); } public function test_farm_name(): void { $item = FarmDirectFactory::new()->create(['tenant_id' => 1]); $this->assertNotEmpty($item->farm_name); } }
